package service.impl;import service.CrudService;import dao.CrudDao;import model.CrudRecord;import exception.ValidationException;import java.util.*;
public class GenericCrudService implements CrudService{private CrudDao<CrudRecord> dao; public GenericCrudService(CrudDao<CrudRecord> dao){this.dao=dao;}
 public void add(CrudRecord r){validate(r);dao.insert(r);} public List<CrudRecord> getAll(){return dao.findAll();} public CrudRecord getById(int id){return dao.findById(id);} public void modify(CrudRecord r){if(r.getId()<=0)throw new ValidationException("請先點選表格資料再修改");validate(r);dao.update(r);} public void remove(int id){if(id<=0)throw new ValidationException("請先點選表格資料再刪除");dao.delete(id);} private void validate(CrudRecord r){if(r.getCol1()==null||r.getCol1().trim().isEmpty())throw new ValidationException("第一欄不可空白");}}
